  ('disabled-7c4986e7-moex-00115', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-113-33fe54d8', 'sub-disabled-7c4986e7-06', NULL, 'essay', 'K 公司預期 EPS 為 $6，公司原本計劃將所有的盈餘全數以股利形式發放
給股東，K公司目前股價為 $60。
K公司的權益資金成本為何？該公司股票的本益比為何？（6分）
現在 K 公司新政策是規劃降低股利支付率至 70%，並使用保留盈餘去
設置新據點。投資新據點的預期報酬率為12%，假設該公司的權益資金
成本不變，請問這個新政策對於該公司股價有何影響？該公司股票的本
益比又為何？比較與的結果並說明原因。（10 分）
另一種情況為現在K公司新政策是規劃降低股利支付率至70%，並使用
保留盈餘去設置新據點。投資新據點的預期報酬率為10%，假設該公司
的權益資金成本不變，請問這個新政策對於該公司股價有何影響？該公
司股票的本益比又為何？比較與的結果並說明原因。（10分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:59+00:00", "source_pdf_sha1": "615f168c553e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "306", "s": "1006", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "財務管理與投資學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL)
